+    if (IsLogical) {
+      if (V == RHS && RHS->hasSameSign()) {
+        RHS->setSameSign(false);
+        addToWorklist(RHS);
+      } else if (V == LHS && LHS->hasSameSign()) {
+        LHS->setSameSign(false);
+        addToWorklist(LHS);
